func (t Types) GetBySuffix(suffix string) (tp Type, si SuffixInfo, found bool) {
	suffix = strings.ToLower(suffix)
	for _, tt := range t {
		if tt.hasSuffix(suffix) {
			if found {

				found = false
				return
			}
			tp = tt
			si = SuffixInfo{
				FullSuffix:	tt.Delimiter + suffix,
				Suffix:		suffix,
			}
			found = true
		}
	}
	return
}
